  "home.gallery.open":    { en: "Open full gallery", ur: "پوری گیلری کھولیں", "ur-roman": "Poori gallery kholein", hi: "पूरी गैलरी खोलें", ar: "افتح المعرض كاملًا" },

  "home.guide.eyebrow":  { en: "Visitor guidelines", ur: "زائرین کے لیے ہدایات", "ur-roman": "Zaireen ke liye hidayat", hi: "आगंतुक दिशानिर्देश", ar: "إرشادات الزائرات" },
  "home.guide.title":    { en: "Come dressed as your favourite self.", ur: "اپنے پسندیدہ روپ میں آئیں۔", "ur-roman": "Apne pasandeeda roop mein aayein.", hi: "अपने पसंदीदा रूप में आएँ।", ar: "تعالي بأحبّ إطلالة إليك." },
  "home.guide.subtitle": { en: "A few gentle notes to help everyone feel warm and welcome on the day.", ur: "چند نرم باتیں تاکہ اس دن سب کو گرمجوشی اور خوش آمدید محسوس ہو۔", "ur-roman": "Chand naram baatein taake us din sab ko garmjoshi aur khush-aamdeed mehsoos ho.", hi: "कुछ कोमल बातें ताकि उस दिन सभी को गर्मजोशी और स्वागत महसूस हो।", ar: "بضع ملاحظات لطيفة ليشعر الجميع بالدفء والترحيب في اليوم." },

  "home.faq.eyebrow": { en: "Frequently asked", ur: "اکثر پوچھے گئے", "ur-roman": "Aksar poochhe gaye", hi: "अक्सर पूछे जाने वाले", ar: "الأسئلة الشائعة" },
  "home.faq.title":   { en: "Everything you might wonder.", ur: "ہر وہ چیز جو آپ سوچ سکتی ہیں۔", "ur-roman": "Har woh cheez jo aap soch sakti hain.", hi: "हर वह बात जो आप सोच सकती हैं।", ar: "كل ما قد يخطر ببالك." },

  "home.cta.badge":    { en: "Season 3 registrations open", ur: "سیزن 3 کی رجسٹریشن کھلی ہے", "ur-roman": "Season 3 ki registration khuli hai", hi: "सीज़न 3 पंजीकरण खुला है", ar: "التسجيل للموسم 3 مفتوح" },
  "home.cta.title":    { en: "Your table at Amcho Bazar is waiting.", ur: "امچو بازار میں آپ کی میز آپ کا انتظار کر رہی ہے۔", "ur-roman": "Amcho Bazar mein aap ki mez aap ka intzar kar rahi hai.", hi: "अम्चो बाज़ार में आपकी मेज़ आपका इंतज़ार कर रही है।", ar: "طاولتك في أمتشو بازار بانتظارك." },
  "home.cta.subtitle": { en: "Whether you cook for your street, stitch after Fajr, or paint on Sundays — bring your home-grown business to the festival. Five simple steps, one warm community.", ur: "چاہے آپ اپنی گلی کے لیے کھانا بناتی ہوں، فجر کے بعد سلائی کرتی ہوں، یا اتوار کو پینٹنگ کرتی ہوں — اپنا گھریلو کاروبار میلے میں لائیں۔ پانچ آسان مراحل، ایک گرم کمیونٹی۔", "ur-roman": "Chahe aap apni gali ke liye khana banati hon, Fajr ke baad silai karti hon, ya itwaar ko painting karti hon — apna gharelu karobar mele mein laayein. Paanch aasan marahil, ek garm community.", hi: "चाहे आप अपनी गली के लिए खाना बनाती हों, फ़ज्र के बाद सिलाई करती हों, या रविवार को पेंटिंग करती हों — अपना घरेलू व्यवसाय उत्सव में लाएँ। पाँच आसान चरण, एक गर्म समुदाय।", ar: "سواء كنتِ تطبخين لحيّك، أو تخيطين بعد الفجر، أو ترسمين أيام الأحد — أحضري عملك المنزلي إلى المهرجان. خمس خطوات بسيطة، ومجتمع دافئ واحد." },
  "home.cta.start":    { en: "Start registration", ur: "رجسٹریشن شروع کریں", "ur-roman": "Registration shuru karein", hi: "पंजीकरण शुरू करें", ar: "ابدئي التسجيل" },
