  "reg.hero.title":    { en: "Bring your home business to the bazaar.", ur: "اپنا گھریلو کاروبار بازار میں لائیں۔", "ur-roman": "Apna gharelu karobar bazaar mein laayein.", hi: "अपना घरेलू व्यवसाय बाज़ार में लाएँ।", ar: "أحضري عملك المنزلي إلى البازار." },
  "reg.hero.subtitle": { en: "Five gentle steps. Save your seat at Nawait's warmest festival.", ur: "پانچ آسان مراحل۔ نوائط کے سب سے گرم میلے میں اپنی جگہ محفوظ کریں۔", "ur-roman": "Paanch aasan marahil. Nawait ke sab se garm mele mein apni jagah mehfooz karein.", hi: "पाँच आसान चरण। नवाइत के सबसे गर्म उत्सव में अपनी जगह सुरक्षित करें।", ar: "خمس خطوات بسيطة. احجزي مكانك في أدفأ مهرجانات نوائط." },
