  "reg.business.h2":  { en: "Tell us about your business", ur: "ہمیں اپنے کاروبار کے بارے میں بتائیں", "ur-roman": "Hamein apne karobar ke baare mein batayein", hi: "हमें अपने व्यवसाय के बारे में बताएँ", ar: "أخبرينا عن عملك" },
  "reg.business.sub": { en: "The name that will greet visitors at your stall.", ur: "وہ نام جو آپ کے اسٹال پر زائرین کا استقبال کرے گا۔", "ur-roman": "Woh naam jo aap ke stall par zaireen ka istaqbaal karega.", hi: "वह नाम जो आपके स्टॉल पर आगंतुकों का स्वागत करेगा।", ar: "الاسم الذي سيرحّب بالزائرات عند كشكك." },
