  "signup.feat3":    { en: "Showcase your craft to the community", ur: "اپنے ہنر کو کمیونٹی کے سامنے پیش کریں", "ur-roman": "Apne hunar ko community ke saamne pesh karein", hi: "अपने शिल्प को समुदाय के सामने प्रस्तुत करें", ar: "اعرضي حرفتك على المجتمع" },
