type Ctx = { lang: Lang; setLang: (l: Lang) => void; t: (k: string) => string; dir: "ltr" | "rtl" };
const I18nContext = createContext<Ctx | null>(null);

const stored = (): Lang => {
  if (typeof window === "undefined") return "en";
  const v = window.localStorage.getItem("lang") as Lang | null;
  return v && LANGS.some((l) => l.code === v) ? v : "en";
};

export function I18nProvider({ children }: { children: ReactNode }) {
  const [lang, setLangState] = useState<Lang>(stored);
  const dir = LANGS.find((l) => l.code === lang)?.dir ?? "ltr";

  // Reflect language + direction on <html> so RTL languages flow correctly.
  useEffect(() => {
    document.documentElement.lang = lang;
    document.documentElement.dir = dir;
  }, [lang, dir]);

  function setLang(l: Lang) {
    setLangState(l);
    if (typeof window !== "undefined") window.localStorage.setItem("lang", l);
  }
  function t(k: string) {
    return T[k]?.[lang] ?? T[k]?.en ?? k;
  }

  return <I18nContext.Provider value={{ lang, setLang, t, dir }}>{children}</I18nContext.Provider>;
}

export function useI18n(): Ctx {
  const c = useContext(I18nContext);
  if (!c) throw new Error("useI18n must be used within an I18nProvider");
  return c;
}
